import { formatClassToStatus } from './format.js';
import { trigger } from '../core/event.js';

/**
 * Describe the boolean status API that will be generated by {@link defBool}.
 *
 * Example:
 * - Input: name = "header-close"
 * - Generated status property on exportObj: "headerClose"
 * - Generated methods on exportObj:
 *   - addHeaderClose()
 *   - removeHeaderClose()
 *   - toggleHeaderClose()
 *   - isHeaderClose()
 * - Optional lifecycle hooks on opt:
 *   - beforeAddHeaderClose
 *   - afterAddHeaderClose
 *   - beforeRemoveHeaderClose
 *   - afterRemoveHeaderClose
 *
 * @param {string} name CSS class name that represents the "on" state (e.g. "header-close")
 * @returns {{
 *   name: string;
 *   statusProp: string;
 *   methodNames: {
 *     add: string;
 *     remove: string;
 *     toggle: string;
 *     is: string;
 *   };
 *   hookNames: {
 *     beforeAdd: string;
 *     afterAdd: string;
 *     beforeRemove: string;
 *     afterRemove: string;
 *   };
 * }}
 */
export function getBoolStatusMeta(name) {
	const statusName = formatClassToStatus(name);
	const eventName = statusName.charAt(0).toUpperCase() + statusName.slice(1);

	return {
		name,
		statusProp: statusName,
		methodNames: {
			add: `add${eventName}`,
			remove: `remove${eventName}`,
			toggle: `toggle${eventName}`,
			is: `is${eventName}`,
		},
		hookNames: {
			beforeAdd: `beforeAdd${eventName}`,
			afterAdd: `afterAdd${eventName}`,
			beforeRemove: `beforeRemove${eventName}`,
			afterRemove: `afterRemove${eventName}`,
		},
	};
}

/**
 * Based on the provided key, make an element switch between true and false status.
 *
 * After calling:
 *   defBool('header-close', $el, opt, exportObj);
 *
 * You can use:
 *   exportObj.addHeaderClose();
 *   exportObj.removeHeaderClose();
 *   exportObj.toggleHeaderClose();
 *   exportObj.isHeaderClose();
 *
 * And optionally define in opt:
 *   opt.beforeAddHeaderClose, opt.afterAddHeaderClose,
 *   opt.beforeRemoveHeaderClose, opt.afterRemoveHeaderClose.
 *
 * @param {string} name the key name / CSS class name that will be used to store the current status
 * @param {HTMLElement} $el the element that will toggle the className `${name}`
 * @param {Object} [opt] options including beforeAddName, afterAddName, beforeRemoveName, afterRemoveName
 * @param {Object} [exportObj] the object that will be injected with addName/removeName/toggleName/isName
 * @returns {Object} the same exportObj reference for chaining or inspection
 */
export function defBool(name, $el, opt, exportObj) {
	const meta = getBoolStatusMeta(name);
	const opts = opt || {};
	const target = exportObj || {};

	const { statusProp, methodNames, hookNames } = meta;

	target[methodNames.add] = () => {
		const before = opts[hookNames.beforeAdd];
		if (before) {
			trigger(before, $el, opts, target);
		}

		$el.classList.add(name);
		target[statusProp] = true;

		const after = opts[hookNames.afterAdd];
		if (after) {
			trigger(after, $el, opts, target);
		}
	};

	target[methodNames.remove] = () => {
		const before = opts[hookNames.beforeRemove];
		if (before) {
			trigger(before, $el, opts, target);
		}

		$el.classList.remove(name);
		target[statusProp] = false;

		const after = opts[hookNames.afterRemove];
		if (after) {
			trigger(after, $el, opts, target);
		}
	};

	target[methodNames.toggle] = () => {
		if ($el.classList.contains(name)) {
			target[methodNames.remove]();
		} else {
			target[methodNames.add]();
		}
	};

	target[methodNames.is] = () => {
		return $el.classList.contains(name);
	};

	return target;
}

/**
 * Describe the enum status API that will be generated by {@link defEnum}.
 *
 * Example:
 * - Input: key = "view", names = ["grid", "detail", "map"]
 * - Generated status property on exportObj: "view"
 * - Generated methods on exportObj:
 *   - switchToGrid()
 *   - switchToDetail()
 *   - switchToMap()
 * - Helper getter method:
 *   - currentView()
 * - CSS classes toggled on $el:
 *   - "view-grid", "view-detail", "view-map"
 * - Optional lifecycle hooks on opt:
 *   - beforeSwitchToGrid / afterSwitchToGrid
 *   - beforeSwitchToDetail / afterSwitchToDetail
 *   - beforeSwitchToMap / afterSwitchToMap
 *
 * @param {string} key the key name that will be used to store the current status
 * @param {string[]} names the values that can be switched to, like ['nameA', 'nameB', 'nameC']
 * @returns {{
 *   statusProp: string;
 *   currentMethodName: string;
 *   values: Array<{
 *     name: string;
 *     statusValue: string;
 *     methodName: string;
 *     hookNames: { before: string; after: string };
 *     className: string;
 *   }>;
 * }}
 */
export function getEnumStatusMeta(key, names) {
	const statusName = formatClassToStatus(key);
	const currentMethodName = `current${formatClassToStatus(key)}`;

	const values = names.map((name) => {
		const statusValue = formatClassToStatus(name);
		const eventName = statusValue.charAt(0).toUpperCase() + statusValue.slice(1);

		return {
			name,
			statusValue,
			methodName: `switchTo${eventName}`,
			hookNames: {
				before: `beforeSwitchTo${eventName}`,
				after: `afterSwitchTo${eventName}`,
			},
			className: `${key}-${name}`,
		};
	});

	return {
		statusProp: statusName,
		currentMethodName,
		values,
	};
}

/**
 * Based on a key and possible values, make an element switch between multiple named statuses.
 *
 * After calling:
 *   defEnum('view', ['grid', 'detail', 'map'], $el, opt, exportObj);
 *
 * You can use:
 *   exportObj.switchToGrid();
 *   exportObj.switchToDetail();
 *   exportObj.switchToMap();
 *   exportObj.currentView(); // read the current value
 *
 * And optionally define in opt:
 *   opt.beforeSwitchToGrid / opt.afterSwitchToGrid,
 *   opt.beforeSwitchToDetail / opt.afterSwitchToDetail,
 *   opt.beforeSwitchToMap / opt.afterSwitchToMap.
 *
 * @param {string} key the key name used to store the current status
 * @param {string[]} names the values that can be switched to like ['nameA', 'nameB', 'nameC']
 * @param {HTMLElement} $el the element that will support the className `${key}-${nameA}`, `${key}-${nameB}`, `${key}-${nameC}`
 * @param {Object} [opt] the options including beforeSwitchToNameA, afterSwitchToNameA
 * @param {Object} [exportObj] the object that will be injected with switchToNameA / switchToNameB / ...
 * @returns {Object} the same exportObj reference for chaining or inspection
 */
export function defEnum(key, names, $el, opt, exportObj) {
	const meta = getEnumStatusMeta(key, names);
	const opts = opt || {};
	const target = exportObj || {};

	const { statusProp, currentMethodName, values } = meta;

	values.forEach((valueMeta) => {
		const { name, methodName, hookNames } = valueMeta;

		target[methodName] = () => {
			if (name !== target[statusProp]) {
				const before = opts[hookNames.before];
				if (before) {
					trigger(before, $el, opts, target);
				}

				names.forEach((item) => {
					if (item !== name) {
						$el.classList.remove(`${key}-${item}`);
					} else {
						$el.classList.add(`${key}-${item}`);
						target[statusProp] = item;
					}
				});

				const after = opts[hookNames.after];
				if (after) {
					trigger(after, $el, opts, target);
				}
			}
		};
	});

	target[currentMethodName] = () => {
		return target[statusProp];
	};

	return target;
}
